172	// TestLadder_Next_UsesRoutingActualPower asserts that the ladder consumes
173	// RoutingActual.Power as the input for next-floor computation. The bead
174	// contract guarantees this field lands as the previous attempt's actual
175	// routed power on RoutingActual; the ladder API takes that integer
176	// directly.
177	func TestLadder_Next_UsesRoutingActualPower(t *testing.T) {
178		// Stand-in for the RoutingActual record carried between attempts.
179		// The field name and type mirror the contract: RoutingActual.Power int.
180		type routingActual struct {
181			Harness  string
182			Provider string
183			Model    string
184			Power    int
185		}
186	
187		l := NewLadder([]agentlib.ModelInfo{viable(50), viable(70), viable(90)})
188	
189		prev := routingActual{
190			Harness:  "claude",
191			Provider: "anthropic",
192			Model:    "some-model",
193			Power:    70,
194		}
195	
196		// The escalation loop sources actualPower from the previous attempt's
197		// RoutingActual.Power and passes it directly to Next.
198		got, err := l.Next(prev.Power)
199		if err != nil {
200			t.Fatalf("Next(prev.Power=%d): unexpected err %v", prev.Power, err)
201		}
202		if got != 90 {
203			t.Fatalf("Next(prev.Power=70): got %d want 90", got)
204		}
205	
206		// And confirm the input value is the only relevant signal — provider,
207		// model, and harness on the routing record never enter the decision.
208		prev.Provider = "different-vendor"
209		prev.Model = "different-model"
210		prev.Harness = "different-harness"
211		got2, err := l.Next(prev.Power)
212		if err != nil {
213			t.Fatalf("Next(prev.Power=70) after vendor swap: unexpected err %v", err)
214		}
215		if got2 != got {
216			t.Fatalf("Next must depend on Power only; got %d then %d", got, got2)
217		}
218	}
